SELECT T1.registered_voters, T1.county_name, T1.population
FROM counties AS T1
WHERE T1.population = (SELECT MAX(population) FROM counties);

SELECT voter_count 
FROM voter_demographics
WHERE voter_count > 2000 AND demographic_id NOT IN (0, 1);

SELECT 
  (SELECT SUM(voter_count) FROM voter_registration WHERE county_id = 1 AND party_id = 0) AS registered_voters,
  (SELECT SUM(voter_count) FROM voter_turnout WHERE county_id = 1 AND party_id = 0) AS turnout;

SELECT SUM(vd.voter_count) AS total_voters
FROM voter_demographics vd
WHERE vd.county_id = 4;

SELECT county_name, registered_voters
FROM counties
WHERE population = (SELECT MAX(population) FROM counties);

SELECT county_name, registered_voters, population
FROM counties
WHERE last_updated LIKE '2023%';
